# Deobfuscated Code

Here's the cleaned-up version:

```javascript
// Constants
const TWO_PI = 6.283;
const GOLDEN_RATIO = 1.618;
const SQRT_HALF = 0.707;

// Physics parameters
const params = {
  attractionRange: 4000,
  repulsionCoeff: 0.004,
  amplification: 0.92,
  centeringForce: 0.0003,
  maxParticles: 40,
  streamDecay: 0.04,
  theta: 0.06
};

// Define nodes (hub + 5 named nodes)
const nodes = [
  { id: 'hub', label: 'Hub', r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: 'alpha', label: 'Alpha', r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: 'beta', label: 'Beta', r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: 'gamma', label: 'Gamma', r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: 'delta', label: 'Delta', r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Define spring connections between nodes
const springs = [
  { a: 'hub', b: 'alpha', rest: 160, k: 0.006 },
  { a: 'hub', b: 'beta', rest: 160, k: 0.005 },
  { a: 'hub', b: 'gamma', rest: 170, k: 0.004 },
  { a: 'hub', b: 'delta', rest: 170, k: 0.004 },
  { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta', rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta', rest: 220, k: 0.002 },
  { a: 'beta', b: 'epsilon', rest: 200, k: 0.002 }
];

// Camera/viewport state
let camera = { x: 400, y: 300, zoom: 1 };
let targetCamera = { x: 400, y: 300, zoom: 1 };

// Particle stream
let particles = [];

function findNode(id) {
  return nodes.find(n => n.id === id);
}

function updatePhysics() {
  // Apply repulsive forces between all nodes
  for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
      let dx = nodes[i].x - nodes[j].x;
      let dy = nodes[i].y - nodes[j].y;
      let dist = Math.sqrt(dx * dx + dy * dy) || 1;
      let force = params.attractionRange / (dist * dist);
      let fx = (dx / dist) * force;
      let fy = (dy / dist) * force;

      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // Apply spring forces
  for (let spring of springs) {
    let nodeA = findNode(spring.a);
    let nodeB = findNode(spring.b);
    if (!nodeA || !nodeB) continue;

    let dx = nodeB.x - nodeA.x;
    let dy = nodeB.y - nodeA.y;
    let dist = Math.sqrt(dx * dx + dy * dy) || 1;
    let stretch = dist - spring.rest;
    let force = (spring.k || params.repulsionCoeff) * stretch;

    nodeA.vx += (dx / dist) * force;
    nodeA.vy += (dy / dist) * force;
    nodeB.vx -= (dx / dist) * force;
    nodeB.vy -= (dy / dist) * force;
  }

  // Apply damping and center pull
  for (let node of nodes) {
    node.vx += (400 - node.x) * params.centeringForce;
    node.vy += (300 - node.y) * params.centeringForce;
    node.vx *= params.amplification;
    node.vy *= params.amplification;
    node.x += node.vx;
    node.y += node.vy;
  }
}

function spawnParticle() {
  if (particles.length >= params.maxParticles) return;

  let sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
  let angle = Math.random() * TWO_PI;
  let speed = (0.3 + Math.random() * SQRT_HALF);

  particles.push({
    x: sourceNode.x,
    y: sourceNode.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * GOLDEN_RATIO * SQRT_HALF
  });
}

function updateParticles() {
  for (let i = particles.length - 1; i >= 0; i--) {
    let p = particles[i];
    p.age++;
    p.x += p.vx;
    p.y += p.vy;
    p.vx *= (1 - params.streamDecay * 0.125);
    p.vy *= (1 - params.streamDecay * 0.125);

    if (p.age >= p.maxAge) {
      particles.splice(i, 1);
    }
  }
}

function updateCamera() {
  camera.x += (targetCamera.x - camera.x) * params.theta;
  camera.y += (targetCamera.y - camera.y) * params.theta;
  camera.zoom += (targetCamera.zoom - camera.zoom) * params.theta;
}

function animate() {
  updatePhysics();
  updateParticles();
  updateCamera();

  if (frameCount % 3 === 0) {
    spawnParticle();
  }
  frameCount++;
}

setInterval(animate, 16); // ~60 FPS
```

## What It Does

This is a **particle physics network visualization** system:

1. **6 interconnected nodes** (hub + 5 named nodes) arranged in a force-directed graph
2. **Physics simulation**:
   - Nodes repel each other
   - Springs connect specific node pairs, creating attractive forces
   - Damping and centering pull keeps system stable
3. **Particle stream**: Continuously spawns particles from random nodes that drift with velocity decay
4. **Camera system**: Smoothly pans/zooms the viewport
5. **Runs at ~60 FPS** with updates every 16ms

The obfuscation used string encoding, variable renaming, and control flow flattening to hide the logic.
